// --- Usage Example (main.dart) ---

Future<void> main() async {
  final apiClient = ApiClient(
    onTokenChanged: (token) async {
      // Persist token to secure storage here
      if (token != null) {
        print('Token saved: ${token.accessToken.substring(0, 10)}...');
      } else {
        print('Token cleared');
      }
    },
  );

  try {
    // 1. Login
    print('--- Logging in ---');
    final token = await apiClient.login(
      email: 'user@example.com',
      password: 'securepassword123',
    );
    print('Logged in. Token expires at: ${token.expiresAt}');

    // 2. Get user profile
    print('\n--- Fetching profile ---');
    final profile = await apiClient.getProfile();
    print('User: ${profile.name} (${profile.email})');

    // 3. Update profile
    print('\n--- Updating profile ---');
    final updatedProfile = await apiClient.updateProfile(
      name: 'Updated Name',
    );
    print('Updated name: ${updatedProfile.name}');

    // 4. Sync data
    print('\n--- Syncing data ---');
    final syncItems = [
      SyncData(
        type: 'note',
        payload: {'title': 'My Note', 'content': 'Hello World'},
      ),
      SyncData(
        type: 'task',
        payload: {'title': 'Buy groceries', 'completed': false},
      ),
    ];

    final syncResult = await apiClient.fullSync(
      localItems: syncItems,
      lastSyncedAt: profile.lastSyncedAt,
    );
    print('Synced ${syncResult.itemsSynced} items, '
        '${syncResult.itemsFailed} failed');

    // 5. Check sync status
    print('\n--- Sync status ---');
    final status = await apiClient.getSyncStatus();
    print('Sync status: $status');

    // 6. Logout
    print('\n--- Logging out ---');
    await apiClient.logout();
    print('Logged out successfully');
  } on AuthenticationException catch (e) {
    print('Auth error: ${e.message}');
  } on NetworkException catch (e) {
    print('Network error: ${e.message}');
  } on ApiException catch (e) {
    print('API error: ${e.message} (status: ${e.statusCode})');
  } finally {
    apiClient.dispose();
  }
}